public int minSteps(String s, String t) {
    int[] s_Count = new int[26];
    int[] t_Count = new int[26];
    for(char c : s.toCharArray()) s_Count[c - 'a']++;
    for(char c : t.toCharArray()) t_Count[c - 'a']++;
    int res = 0;
    for(int i = 0; i < 26; i++) {
        res += Math.abs(s_Count[i] - t_Count[i]);
    }
    return res / 2;
}
```

